#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main() {
    int frames[] = {1, 2, 3, 4, 5};
    int n = 5;
    int i = 0;
    int ack;

    printf("Sender: Sending frames...\n");

    while (i < n) {
        printf("\nSending Frame %d...\n", frames[i]);
        printf("Waiting for ACK...\n");

        // Simulate network delay or loss
        sleep(1);

        // Simulate random ACK reception (1 = success, 0 = lost)
        ack = rand() % 2;

        if (ack == 1) {
            printf("Received ACK for Frame %d\n", frames[i]);
            i++; // Move to next frame
        } else {
            printf("Timeout! ACK not received for Frame %d\n", frames[i]);
            printf("Retransmitting Frame %d...\n", frames[i]);
        }
    }

    printf("\nAll frames sent successfully!\n");
    return 0;
}
